def sigungu_to_city(sigungu_cd: str | None) -> str:
    """sigungu_cd 5자리 → ems_transformer 도시명 (소문자). 미매칭 시 'seoul'."""
    if not sigungu_cd:
        return "seoul"
    prefix = str(sigungu_cd)[:2]
    return SIGUNGU_TO_CITY.get(prefix, "seoul")
